parameters.code:
self.cols = 6
self.rows = 6
self.tile = 96
self.ox = 112
self.oy = 140
self.palette = [(214, 69, 65), (65, 105, 225), (60, 179, 113), (244, 208, 63)]
self.grid = []
for gy in range(self.rows):
    row = []
    for gx in range(self.cols):
        n = random.randrange(4)
        while (gx >= 2 and row[gx - 1] == n and row[gx - 2] == n) or (gy >= 2 and self.grid[gy - 1][gx] == n and self.grid[gy - 2][gx] == n):
            n = random.randrange(4)
        row.append(n)
    self.grid.append(row)
self.sel = None
self.score = 0
self.target = 500
self.won = False
self.marked = set()
self.flash = 0
self.flash_total = 36
self.falling = {}
self.fall_speed = 12

def find_matches(g, rows, cols):
    marks = set()
    for yy in range(rows):
        run = 1
        for xx in range(1, cols + 1):
            if xx < cols and g[yy][xx] == g[yy][xx - 1]:
                run = run + 1
            else:
                if run >= 3:
                    for k in range(xx - run, xx):
                        marks.add((k, yy))
                run = 1
    for xx in range(cols):
        run = 1
        for yy in range(1, rows + 1):
            if yy < rows and g[yy][xx] == g[yy - 1][xx]:
                run = run + 1
            else:
                if run >= 3:
                    for k in range(yy - run, yy):
                        marks.add((xx, k))
                run = 1
    return marks

self.find_matches = find_matches

if self.flash > 0:
    self.flash = self.flash - 1
    if self.flash == 0:
        g = self.grid
        marks = self.marked
        self.score = self.score + len(marks) * 10
        falls = {}
        for xx in range(self.cols):
            kept = []
            for yy in range(self.rows):
                if (xx, yy) not in marks:
                    kept.append((yy, g[yy][xx]))
            new_count = self.rows - len(kept)
            for i in range(len(kept)):
                dst = new_count + i
                src = kept[i][0]
                g[dst][xx] = kept[i][1]
                if dst != src:
                    falls[(xx, dst)] = (dst - src) * self.tile
            for dst in range(new_count):
                g[dst][xx] = random.randrange(4)
                falls[(xx, dst)] = new_count * self.tile
        self.marked = set()
        self.falling = falls
        if self.score >= self.target:
            self.won = True
        if not falls:
            new_marks = self.find_matches(g, self.rows, self.cols)
            if new_marks:
                self.marked = new_marks
                self.flash = self.flash_total
elif self.falling:
    done = True
    for key in list(self.falling.keys()):
        v = self.falling[key] - self.fall_speed
        if v > 0:
            self.falling[key] = v
            done = False
        else:
            self.falling[key] = 0
    if done:
        self.falling = {}
        new_marks = self.find_matches(self.grid, self.rows, self.cols)
        if new_marks:
            self.marked = new_marks
            self.flash = self.flash_total

q = self._draw_queue
q.append({'type': 'rectangle', 'x1': self.ox - 10, 'y1': self.oy - 10, 'x2': self.ox + self.cols * self.tile + 10, 'y2': self.oy + self.rows * self.tile + 10, 'color': (52, 73, 94), 'filled': True})
blink_on = self.flash > 0 and (self.flash // 6) % 2 == 0
board_top = self.oy
for gy in range(self.rows):
    for gx in range(self.cols):
        c = self.palette[self.grid[gy][gx]]
        off = self.falling.get((gx, gy), 0)
        x1 = self.ox + gx * self.tile + 4
        y1 = self.oy + gy * self.tile + 4 - off
        y2 = y1 + self.tile - 8
        if y2 <= board_top:
            continue
        if y1 < board_top:
            y1 = board_top
        if (gx, gy) in self.marked:
            if blink_on:
                c = (255, 255, 255)
            q.append({'type': 'rectangle', 'x1': x1, 'y1': y1, 'x2': x1 + self.tile - 8, 'y2': y2, 'color': c, 'filled': True})
            for k in range(3):
                q.append({'type': 'rectangle', 'x1': x1 + k, 'y1': y1 + k, 'x2': x1 + self.tile - 8 - k, 'y2': y2 - k, 'color': (255, 255, 255), 'filled': False})
        else:
            q.append({'type': 'rectangle', 'x1': x1, 'y1': y1, 'x2': x1 + self.tile - 8, 'y2': y2, 'color': c, 'filled': True})
if self.sel is not None:
    for k in range(4):
        x1 = self.ox + self.sel[0] * self.tile + k
        y1 = self.oy + self.sel[1] * self.tile + k
        q.append({'type': 'rectangle', 'x1': x1, 'y1': y1, 'x2': x1 + self.tile - 2 * k, 'y2': y1 + self.tile - 2 * k, 'color': (255, 255, 255), 'filled': False})
q.append({'type': 'text', 'x': self.ox, 'y': self.oy - 56, 'text': 'Score: ' + str(self.score) + '   (win at ' + str(self.target) + ')', 'color': (30, 30, 30)})
q.append({'type': 'text', 'x': self.ox, 'y': self.oy + self.rows * self.tile + 26, 'text': 'Click a tile, then an adjacent tile to swap. Match 3+ in a row.', 'color': (60, 60, 60)})
if self.won:
    q.append({'type': 'text', 'x': self.ox + 190, 'y': self.oy - 96, 'text': 'YOU WIN!', 'color': (200, 30, 30)})
